/**
 * Integration tests for `prismatic-refraction.ts` — empirical witness of
 * every theorem in `ForkRaceFoldTheorems.PrismaticRefraction.lean`.
 *
 * Each test group pairs one or more Lean theorems with a property-based
 * runtime check. Randomized inputs use a seeded LCG so failures are
 * reproducible. The load-bearing test is `wireToStorage` end-to-end,
 * which witnesses `THM-WIRE-TO-STORAGE-IS-SOUND`.
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import {
  assignLane,
  betaOneDeficit,
  byteToShard,
  createRawStream,
  createStorageGate,
  disjointLaneFold,
  foldCompatible,
  isGaugeInvisible,
  prism,
  refract,
  refractStep,
  settleByLane,
  storageAssembly,
  totalPayloadLength,
  wireToStorage,
  type Shard,
} from '../prismatic-refraction';

// ─── Seeded PRNG for reproducible property tests ─────────────────────

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s;
  };
}

function randomBytes(seed: number, n: number): number[] {
  const rng = lcg(seed);
  const out = new Array<number>(n);
  for (let i = 0; i < n; i++) out[i] = rng() & 0xff;
  return out;
}

// ─── Part I: App Contract ────────────────────────────────────────────

describe('PrismaticRefraction — Part I: App contract is shapeless', () => {
  it('THM-APP-CONTRACT-IS-SHAPELESS — any byte array is a valid stream', () => {
    const empty = createRawStream([]);
    const single = createRawStream([42]);
    const long = createRawStream(randomBytes(1, 10_000));
    expect(empty.bytes.length).toBe(0);
    expect(single.bytes.length).toBe(1);
    expect(long.bytes.length).toBe(10_000);
  });
});

// ─── Part II: Wire-Layer Prism ───────────────────────────────────────

describe('PrismaticRefraction — Part II: Wire-layer prism', () => {
  it('THM-PRISM-IS-DETERMINISTIC — same inputs yield same output (structural)', () => {
    for (let seed = 1; seed <= 10; seed++) {
      const stream = createRawStream(randomBytes(seed, 256));
      for (const k of [1, 4, 8, 16]) {
        const a = prism(stream, k);
        const b = prism(stream, k);
        expect(a.length).toBe(b.length);
        for (let i = 0; i < a.length; i++) {
          expect(a[i]!.laneId).toBe(b[i]!.laneId);
          expect(a[i]!.phase).toBe(b[i]!.phase);
          expect(a[i]!.payload.join(',')).toBe(b[i]!.payload.join(','));
        }
      }
    }
  });

  it('THM-PRISM-LANE-COUNT — output length equals input byte count', () => {
    for (let n = 0; n < 200; n++) {
      const stream = createRawStream(randomBytes(n + 17, n));
      for (const k of [1, 2, 4, 8, 16]) {
        expect(prism(stream, k).length).toBe(n);
      }
    }
  });

  it('THM-PRISM-PRESERVES-BYTE-COUNT — total payload = input length', () => {
    for (let seed = 1; seed <= 20; seed++) {
      const n = 500 + (seed * 37) % 1000;
      const stream = createRawStream(randomBytes(seed, n));
      for (const k of [1, 3, 7, 11, 16]) {
        expect(totalPayloadLength(prism(stream, k))).toBe(n);
      }
    }
  });

  it('THM-PRISM-RESPECTS-LANE-BOUND — every laneId ∈ [0, k)', () => {
    for (let seed = 1; seed <= 20; seed++) {
      const stream = createRawStream(randomBytes(seed, 2048));
      for (const k of [1, 2, 4, 8, 16]) {
        for (const s of prism(stream, k)) {
          expect(s.laneId).toBeGreaterThanOrEqual(0);
          expect(s.laneId).toBeLessThan(k);
        }
      }
    }
  });

  it('assignLane rejects non-positive laneCount', () => {
    expect(() => assignLane(5, 0)).toThrow();
    expect(() => assignLane(5, -1)).toThrow();
  });
});

// ─── Part III: Encounter Refraction ──────────────────────────────────

describe('PrismaticRefraction — Part III: Encounter refraction', () => {
  it('THM-REFRACT-PRESERVES-PAYLOAD-ON-FOLD', () => {
    for (let seed = 1; seed <= 50; seed++) {
      const rng = lcg(seed);
      const lane = rng() & 0xf;
      const a: Shard = { laneId: lane, phase: rng() & 0xff, payload: [rng() & 0xff, rng() & 0xff] };
      const b: Shard = { laneId: lane, phase: rng() & 0xff, payload: [rng() & 0xff, rng() & 0xff, rng() & 0xff] };
      const r = refract(a, b);
      expect(r).not.toBeNull();
      expect(r!.payload.length).toBe(a.payload.length + b.payload.length);
    }
  });

  it('THM-REFRACT-RETURNS-NONE-ON-INCOMPATIBLE', () => {
    const a: Shard = { laneId: 3, phase: 0, payload: [1, 2] };
    const b: Shard = { laneId: 7, phase: 0, payload: [3, 4] };
    expect(refract(a, b)).toBeNull();
    expect(foldCompatible(a, b)).toBe(false);
  });

  it('THM-REFRACT-COMMUTES-ON-SINGLE-LANE (phase + payload length)', () => {
    for (let seed = 1; seed <= 50; seed++) {
      const rng = lcg(seed);
      const lane = rng() & 0xf;
      const a: Shard = { laneId: lane, phase: rng() & 0xff, payload: [rng() & 0xff] };
      const b: Shard = { laneId: lane, phase: rng() & 0xff, payload: [rng() & 0xff, rng() & 0xff] };
      const r1 = refract(a, b)!;
      const r2 = refract(b, a)!;
      expect(r1.laneId).toBe(r2.laneId);
      expect(r1.phase).toBe(r2.phase);
      expect(r1.payload.length).toBe(r2.payload.length);
    }
  });
});

// ─── Part IV: Disjoint-Lane Commutativity ────────────────────────────

describe('PrismaticRefraction — Part IV: Disjoint-lane commutativity', () => {
  it('THM-DISJOINT-LANE-ENCOUNTERS-COMMUTE — lane-disjoint results', () => {
    const a: Shard = { laneId: 2, phase: 1, payload: [10] };
    const b: Shard = { laneId: 2, phase: 2, payload: [20] };
    const c: Shard = { laneId: 5, phase: 3, payload: [30] };
    const d: Shard = { laneId: 5, phase: 4, payload: [40] };
    const out = disjointLaneFold(a, b, c, d);
    expect(out).not.toBeNull();
    expect(out!.r1.laneId).toBe(a.laneId);
    expect(out!.r2.laneId).toBe(c.laneId);
    expect(out!.r1.laneId).not.toBe(out!.r2.laneId);
  });

  it('returns null when a,b share a lane with c,d', () => {
    const a: Shard = { laneId: 3, phase: 0, payload: [] };
    const b: Shard = { laneId: 3, phase: 0, payload: [] };
    const c: Shard = { laneId: 3, phase: 0, payload: [] };
    const d: Shard = { laneId: 3, phase: 0, payload: [] };
    expect(disjointLaneFold(a, b, c, d)).toBeNull();
  });
});

// ─── Part V: β₁ Deficit Monotone Decrease ────────────────────────────

describe('PrismaticRefraction — Part V: β₁ deficit', () => {
  it('THM-SUCCESSFUL-REFRACTION-DECREASES-DEFICIT — head-fold is -1', () => {
    const shards: Shard[] = [
      { laneId: 1, phase: 0, payload: [1] },
      { laneId: 1, phase: 0, payload: [2] },
      { laneId: 2, phase: 0, payload: [3] },
    ];
    const before = betaOneDeficit(shards);
    const { result, folded } = refractStep(shards);
    expect(folded).toBe(true);
    expect(betaOneDeficit(result) + 1).toBe(before);
  });

  it('THM-REFRACTION-NEVER-INCREASES-DEFICIT — failed fold leaves list', () => {
    const shards: Shard[] = [
      { laneId: 1, phase: 0, payload: [1] },
      { laneId: 2, phase: 0, payload: [2] },
      { laneId: 3, phase: 0, payload: [3] },
    ];
    const before = betaOneDeficit(shards);
    const { result, folded } = refractStep(shards);
    expect(folded).toBe(false);
    expect(betaOneDeficit(result)).toBe(before);
  });

  it('settleByLane hits a floor: one shard per distinct lane', () => {
    for (let seed = 1; seed <= 20; seed++) {
      const stream = createRawStream(randomBytes(seed, 1024));
      for (const k of [1, 4, 8, 16]) {
        const shards = prism(stream, k);
        const settled = settleByLane(shards);
        const distinctLanes = new Set(shards.map((s) => s.laneId));
        expect(settled.length).toBe(distinctLanes.size);
        expect(settled.length).toBeLessThanOrEqual(k);
        // Payload is still preserved end-to-end.
        expect(totalPayloadLength(settled)).toBe(stream.bytes.length);
      }
    }
  });
});

// ─── Part VI: Gauge-Invisibility ─────────────────────────────────────

describe('PrismaticRefraction — Part VI: Gauge invisibility', () => {
  it('THM-GAUGE-INVISIBLE-IS-COMPLETE — lone-lane shard has no compatible partner', () => {
    const s: Shard = { laneId: 7, phase: 0, payload: [42] };
    const others: Shard[] = [
      { laneId: 0, phase: 0, payload: [] },
      { laneId: 1, phase: 0, payload: [] },
      { laneId: 3, phase: 0, payload: [] },
    ];
    expect(isGaugeInvisible(s, others)).toBe(true);
    for (const o of others) expect(refract(s, o)).toBeNull();
  });

  it('returns false when any other shard shares the lane', () => {
    const s: Shard = { laneId: 5, phase: 0, payload: [] };
    const others: Shard[] = [
      { laneId: 1, phase: 0, payload: [] },
      { laneId: 5, phase: 0, payload: [] },
    ];
    expect(isGaugeInvisible(s, others)).toBe(false);
  });
});

// ─── Part VII: Storage Gate ──────────────────────────────────────────

describe('PrismaticRefraction — Part VII: Storage gate', () => {
  it('THM-STORAGE-ONLY-SEES-ADMISSIBLE-LANES', () => {
    const gate = createStorageGate([2, 5, 7], 42);
    const shards: Shard[] = [0, 2, 4, 5, 7, 9].map((laneId) => ({
      laneId,
      phase: 0,
      payload: [],
    }));
    const survivors = storageAssembly(gate, shards);
    for (const s of survivors) {
      expect(gate.admissibleLanes).toContain(s.laneId);
    }
    expect(survivors.length).toBe(3);
  });

  it('THM-STORAGE-ASSEMBLY-IS-IDEMPOTENT (membership form)', () => {
    const gate = createStorageGate([1, 3, 5], 1);
    for (let seed = 1; seed <= 20; seed++) {
      const stream = createRawStream(randomBytes(seed, 256));
      const shards = prism(stream, 8);
      const once = storageAssembly(gate, shards);
      const twice = storageAssembly(gate, once);
      expect(twice.length).toBe(once.length);
      for (let i = 0; i < once.length; i++) {
        expect(once[i]!.laneId).toBe(twice[i]!.laneId);
      }
    }
  });

  it('createStorageGate rejects bad input', () => {
    expect(() => createStorageGate([1, -1], 0)).toThrow();
    expect(() => createStorageGate([1, 1.5], 0)).toThrow();
    expect(() => createStorageGate([0], -1)).toThrow();
  });
});

// ─── Part VIII: Storage-Shape Soundness (Crown) ──────────────────────

describe('PrismaticRefraction — Part VIII: Wire-to-storage soundness', () => {
  it('THM-WIRE-TO-STORAGE-IS-SOUND — lanes bounded, payload preserved', () => {
    for (let seed = 1; seed <= 50; seed++) {
      const n = 500 + (seed * 73) % 2500;
      const stream = createRawStream(randomBytes(seed, n));
      for (const k of [1, 2, 4, 8, 16]) {
        const w = wireToStorage(stream, k);
        expect(w.lanesBounded).toBe(true);
        expect(w.payloadPreserved).toBe(true);
        expect(w.totalBytes).toBe(n);
        expect(w.shardCount).toBe(n);
        expect(w.settled.length).toBeLessThanOrEqual(k);
        // Post-settle payload also totals n.
        expect(totalPayloadLength(w.settled)).toBe(n);
        for (const s of w.settled) {
          expect(s.laneId).toBeGreaterThanOrEqual(0);
          expect(s.laneId).toBeLessThan(k);
        }
      }
    }
  });

  it('region-parallel determinism: two independent pipelines agree', () => {
    // Simulates knotgraph's `race_deterministic` constraint: two
    // workers in different regions given the same (stream, k) must
    // produce identical settled shards.
    for (let seed = 1; seed <= 20; seed++) {
      const stream = createRawStream(randomBytes(seed, 4096));
      const w1 = wireToStorage(stream, 8);
      const w2 = wireToStorage(stream, 8);
      expect(w1.settled.length).toBe(w2.settled.length);
      for (let i = 0; i < w1.settled.length; i++) {
        expect(w1.settled[i]!.laneId).toBe(w2.settled[i]!.laneId);
        expect(w1.settled[i]!.phase).toBe(w2.settled[i]!.phase);
        expect(w1.settled[i]!.payload.join(',')).toBe(w2.settled[i]!.payload.join(','));
      }
    }
  });

  it('rejects k > 16 (knotgraph app-zone width)', () => {
    const stream = createRawStream([1, 2, 3]);
    expect(() => wireToStorage(stream, 17)).toThrow();
    expect(() => wireToStorage(stream, 0)).toThrow();
  });

  it('end-to-end: raw bytes → wireToStorage → storage gate', () => {
    // Full pipeline: app vomits 8 KB, wire sorts to k=16 lanes,
    // storage gate admits only even-numbered lanes.
    const stream = createRawStream(randomBytes(7, 8192));
    const w = wireToStorage(stream, 16);
    const gate = createStorageGate([0, 2, 4, 6, 8, 10, 12, 14], 1);
    const admitted = storageAssembly(gate, w.settled);
    // Every admitted shard is on an even lane.
    for (const s of admitted) {
      expect(s.laneId % 2).toBe(0);
    }
    // Every admitted shard's payload is reachable from the original stream.
    const admittedBytes = new Set<number>();
    for (const s of admitted) for (const b of s.payload) admittedBytes.add(b);
    for (const b of admittedBytes) expect(stream.bytes).toContain(b);
  });
});
